const axios = require('axios');
const issueId = $ticket;
try {
  const auth = 'Basic ' + Buffer.from($vars.ATLASSIAN_EMAIL + ':' + $vars.ATLASSIAN_TOKEN).toString('base64');

  const res = await axios.get(`${$vars.ATLASSIAN_HOST}/rest/api/3/issue/${issueId}`, {
    headers: { 'Authorization': auth, 'Accept': 'application/json' }
  });

  const json = res.data;
  const summary = json.fields.summary || "No Summary";
  const status = json.fields.status?.name || "Unknown Status";
  const labels = json.fields.labels ? json.fields.labels.join(', ') : "None";
  const attachments = (json.fields.attachment || []).map(a => {
      return `\n- Name: ${a.filename}\n  URL: ${a.content}`;
  }).join('');

  return `ISSUE: ${issueId}\nSUMMARY: ${summary}\nSTATUS: ${status}\nLABELS: ${labels}\nATTACHMENTS: ${attachments || 'None'}`;
} catch (e) {
  return "ERROR: " + (e.response ? e.response.status : e.message);
}
